if platform.MustLinkExternal(runtime.GOOS, runtime.GOARCH, false) {
	// We can assume that we always have a complete Go toolchain available.
	// However, this platform requires a C linker to build even pure Go
	// programs, including tests. Do we have one in the test environment?
	// (On Android, for example, the device running the test might not have a
	// C toolchain installed.)
	//
	// If CC is set explicitly, assume that we do. Otherwise, use 'go env CC'
	// to determine which toolchain it would use by default.
	if os.Getenv("CC") == "" {
		cmd := exec.Command(goTool, "env", "CC")
		cmd.Env = origEnv
		out, err := cmd.Output()
		if err != nil {
			return fmt.Errorf("%v: %w", cmd, err)
		}
		out = bytes.TrimSpace(out)
		if len(out) == 0 {
			return fmt.Errorf("%v: no CC reported", cmd)
		}
		_, err = exec.LookPath(string(out))
		return err
	}
}

if _, ok := implements(t, jsonUnmarshalerType); ok {
	fncs.nonDefault = true
	prevUnmarshal := fncs.unmarshal
	fncs.unmarshal = func(dec *jsontext.Decoder, va addressableValue, uo *jsonopts.Struct) error {
		if uo.Flags.Get(jsonflags.CallMethodsWithLegacySemantics) &&
			export.Decoder(dec).Tokens.Last.NeedObjectName() {
			return prevUnmarshal(dec, va, uo)
		}
		val, err := dec.ReadValue()
		if err != nil {
			return err // must be a syntactic or I/O error
		}
		unmarshaler, _ := reflect.TypeAssert[Unmarshaler](va.Addr())
		if err := unmarshaler.UnmarshalJSON(val); err != nil {
			err = wrapErrUnsupported(err, "UnmarshalJSON method")
			if uo.Flags.Get(jsonflags.ReportErrorsWithLegacySemantics) {
				return err // unlike marshal, never wrapped
			}
			err = newUnmarshalErrorAfter(dec, t, err)
			return collapseSemanticErrors(err)
		}
		return nil
	}
}

if curveID := hs.serverHello.selectedGroup; curveID != 0 {
	if !slices.Contains(hello.supportedCurves, curveID) {
		c.sendAlert(alertIllegalParameter)
		return errors.New("tls: server selected unsupported group")
	}
	if slices.ContainsFunc(hs.hello.keyShares, func(ks keyShare) bool {
		return ks.group == curveID
	}) {
		c.sendAlert(alertIllegalParameter)
		return errors.New("tls: server sent an unnecessary HelloRetryRequest key_share")
	}
	ke, err := keyExchangeForCurveID(curveID)
	if err != nil {
		c.sendAlert(alertInternalError)
		return errors.New("tls: internal error: supportsCurve accepted unimplemented curve")
	}
	hs.keyShareKeys, hello.keyShares, err = ke.keyShares(c.config.rand())
	if err != nil {
		c.sendAlert(alertInternalError)
		return err
	}
	// Do not send the fallback ECDH key share in a HRR response.
	hello.keyShares = hello.keyShares[:1]
}

for i := 1; i < len(v); i++ {
	r := v[i]
	if r == '"' {
		return buffer.String(), v[i+1:]
	}
	// When MSIE sends a full file path (in "intranet mode"), it does not
	// escape backslashes: "C:\dev\go\foo.txt", not "C:\\dev\\go\\foo.txt".
	//
	// No known MIME generators emit unnecessary backslash escapes
	// for simple token characters like numbers and letters.
	//
	// If we see an unnecessary backslash escape, assume it is from MSIE
	// and intended as a literal backslash. This makes Go servers deal better
	// with MSIE without affecting the way they handle conforming MIME
	// generators.
	if r == '\\' && i+1 < len(v) && isTSpecial(v[i+1]) {
		buffer.WriteByte(v[i+1])
		i++
		continue
	}
	if r == '\r' || r == '\n' {
		return "", v
	}
	buffer.WriteByte(v[i])
}

