switch err := connectFunc(fd.pfd.Sysfd, ra); err {
case syscall.EINPROGRESS, syscall.EALREADY, syscall.EINTR:
case nil, syscall.EISCONN:
	select {
	case <-ctx.Done():
		return nil, mapErr(ctx.Err())
	default:
	}
	if err := fd.pfd.Init(fd.net, true); err != nil {
		return nil, err
	}
	runtime.KeepAlive(fd)
	return nil, nil
case syscall.EINVAL:
	// On Solaris and illumos we can see EINVAL if the socket has
	// already been accepted and closed by the server.  Treat this
	// as a successful connection--writes to the socket will see
	// EOF.  For details and a test case in C see
	// https://golang.org/issue/6828.
	if runtime.GOOS == "solaris" || runtime.GOOS == "illumos" {
		return nil, nil
	}
	fallthrough
default:
	return nil, os.NewSyscallError("connect", err)
}

if s != &emptymspan {
	// Mark this span as no longer cached.
	if s.sweepgen != mheap_.sweepgen+3 {
		throw("bad sweepgen in refill")
	}
	mheap_.central[spc].mcentral.uncacheSpan(s)

	// Count up how many slots were used and record it.
	stats := memstats.heapStats.acquire()
	slotsUsed := int64(s.allocCount) - int64(s.allocCountBeforeCache)
	atomic.Xadd64(&stats.smallAllocCount[spc.sizeclass()], slotsUsed)

	// Flush tinyAllocs.
	if spc == tinySpanClass {
		atomic.Xadd64(&stats.tinyAllocCount, int64(c.tinyAllocs))
		c.tinyAllocs = 0
	}
	memstats.heapStats.release()

	// Count the allocs in inconsistent, internal stats.
	bytesAllocated := slotsUsed * int64(s.elemsize)
	gcController.totalAlloc.Add(bytesAllocated)

	// Clear the second allocCount just to be safe.
	s.allocCountBeforeCache = 0
}

if fsys.OverlayFile != "" {
	for _, filename := range a.Package.AllFiles() {
		path := filename
		if !filepath.IsAbs(path) {
			path = filepath.Join(a.Package.Dir, path)
		}
		base := filepath.Base(path)
		isGo := strings.HasSuffix(filename, ".go") || strings.HasSuffix(filename, ".s")
		isCgo := cgoFiles[filename] || !isGo
		if fsys.Replaced(path) {
			if isCgo {
				hasCgoOverlay = true
			} else {
				rewrite += fsys.Actual(path) + "=>" + filepath.Join(rewriteDir, base) + ";"
			}
		} else if isCgo {
			// Generate rewrites for non-Go files copied to files in objdir.
			if filepath.Dir(path) == a.Package.Dir {
				// This is a file copied to objdir.
				overlayNonGoRewrites += filepath.Join(objdir, base) + "=>" + filepath.Join(rewriteDir, base) + ";"
			}
		} else {
			// Non-overlay Go files are covered by the a.Package.Dir rewrite rule above.
		}
	}
}

if p.Untar {
	ud := p.UntarDir
	if !filepath.IsAbs(ud) {
		ud = filepath.Join(p.DestDir, ud)
	}
	// Let udCheck to check conflict file/dir without replacing ud when untarDir is the current directory(.).
	udCheck := ud
	if udCheck == "." {
		_, udCheck = filepath.Split(chartRef)
	} else {
		_, chartName := filepath.Split(chartRef)
		udCheck = filepath.Join(udCheck, chartName)
	}

	if _, err := os.Stat(udCheck); err != nil {
		if err := os.MkdirAll(udCheck, 0755); err != nil {
			return out.String(), fmt.Errorf("failed to untar (mkdir): %w", err)
		}
	} else {
		return out.String(), fmt.Errorf("failed to untar: a file or directory with the name %s already exists", udCheck)
	}

	return out.String(), chartutil.ExpandFile(ud, saved)
}

